const express = require('express');
const router = express.Router();

// Middleware to verify authentication
const requireAuth = (req, res, next) => {
  if (!req.user || !req.user.id || !req.user.companyId) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  next();
};

// Middleware to verify tenant isolation
const verifyTenantAccess = (resourceCompanyId) => {
  return (req, res, next) => {
    if (req.user.companyId !== resourceCompanyId) {
      return res.status(403).json({ error: 'Forbidden: Access denied to this resource' });
    }
    next();
  };
};

// Role-based access control middleware
const requireRole = (...allowedRoles) => {
  return (req, res, next) => {
    if (!req.user.role || !allowedRoles.includes(req.user.role)) {
      return res.status(403).json({ error: 'Forbidden: Insufficient permissions' });
    }
    next();
  };
};

// Field-level authorization for updates
const validateUpdateFields = (allowedFields, roleFieldMap) => {
  return (req, res, next) => {
    const requestedFields = Object.keys(req.body);
    const userRole = req.user.role;
    
    let permittedFields = allowedFields;
    if (roleFieldMap && roleFieldMap[userRole]) {
      permittedFields = roleFieldMap[userRole];
    }
    
    const unauthorizedFields = requestedFields.filter(
      field => !permittedFields.includes(field)
    );
    
    if (unauthorizedFields.length > 0) {
      return res.status(403).json({ 
        error: 'Forbidden: Cannot update fields', 
        unauthorizedFields 
      });
    }
    
    next();
  };
};

